import os
from cryptography.fernet import Fernet

def encrypt_credit_card(cc_number):
    # Generate a new encryption key if it doesn't exist
    if not os.path.exists("encryption_key"):
        encryption_key = Fernet.generate_key()
        with open("encryption_key", "wb") as f:
            f.write(encryption_key)

    # Read the existing encryption key from file
    with open("encryption_key", "rb") as f:
        encryption_key = f.read()

    # Encrypt the credit card number using the Fernet algorithm
    encrypted_cc_number = Fernet(encryption_key).encrypt(cc_number)

    return encrypted_cc_number

def decrypt_credit_card(encrypted_cc_number):
    # Read the existing encryption key from file
    with open("encryption_key", "rb") as f:
        encryption_key = f.read()

    # Decrypt the credit card number using the Fernet algorithm
    decrypted_cc_number = Fernet(encryption_key).decrypt(encrypted_cc_number)

    return decrypted_cc_number